from fastapi import FastAPI, Depends, HTTPException, status, Header
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from typing import Optional, Dict, Any
import redis.asyncio as redis
from contextlib import asynccontextmanager
import json


redis_client: Optional[redis.Redis] = None


@asynccontextmanager
async def lifespan(app: FastAPI):
    global redis_client
    redis_client = await redis.from_url(
        "redis://localhost:6379",
        encoding="utf-8",
        decode_responses=True,
        max_connections=50
    )
    yield
    await redis_client.close()


app = FastAPI(lifespan=lifespan)

security = HTTPBearer()


class TokenValidator:
    def __init__(self, redis_client: redis.Redis):
        self.redis_client = redis_client
        self.token_prefix = "oauth_token:"
    
    async def validate_token(self, token: str) -> Dict[str, Any]:
        token_key = f"{self.token_prefix}{token}"
        token_data = await self.redis_client.get(token_key)
        
        if not token_data:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Invalid or expired token",
                headers={"WWW-Authenticate": "Bearer"}
            )
        
        try:
            return json.loads(token_data)
        except json.JSONDecodeError:
            raise HTTPException(
                status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,
                detail="Token data corrupted"
            )
    
    async def get_user_from_token(self, token: str) -> Dict[str, Any]:
        token_data = await self.validate_token(token)
        return token_data


def get_redis_client() -> redis.Redis:
    if redis_client is None:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis connection not available"
        )
    return redis_client


def get_token_validator(redis_client: redis.Redis = Depends(get_redis_client)) -> TokenValidator:
    return TokenValidator(redis_client)


async def get_current_user(
    credentials: HTTPAuthorizationCredentials = Depends(security),
    validator: TokenValidator = Depends(get_token_validator)
) -> Dict[str, Any]:
    token = credentials.credentials
    user_data = await validator.get_user_from_token(token)
    return user_data


async def get_optional_user(
    authorization: Optional[str] = Header(None),
    validator: TokenValidator = Depends(get_token_validator)
) -> Optional[Dict[str, Any]]:
    if not authorization:
        return None
    
    if not authorization.startswith("Bearer "):
        return None
    
    token = authorization.replace("Bearer ", "")
    
    try:
        user_data = await validator.get_user_from_token(token)
        return user_data
    except HTTPException:
        return None


