@app.post("/token/store")
async def store_token(
    token: str,
    user_data: Dict[str, Any],
    ttl: int = 3600,
    redis_client: redis.Redis = Depends(get_redis_client)
):
    token_key = f"oauth_token:{token}"
    await redis_client.setex(
        token_key,
        ttl,
        json.dumps(user_data)
    )
    return {"message": "Token stored successfully", "expires_in": ttl}


